'use client';

import * as React from 'react';
import Link from 'next/link';
import { usePathname, useRouter } from 'next/navigation';
import { Button } from '@/components/ui/button';
import { AuthDialog } from '@/components/AuthDialog';

type MeResponse =
  | { success: true; user: { id: string; email: string; name: string } }
  | { success: false; error: string };

async function fetchMe(): Promise<MeResponse> {
  const res = await fetch('/api/auth/me', { method: 'GET', credentials: 'include', cache: 'no-store' });
  const json = (await res.json()) as MeResponse;
  if (!res.ok) return json;
  return json;
}

export function AppHeader() {
  const router = useRouter();
  const pathname = usePathname();

  const [me, setMe] = React.useState<MeResponse | null>(null);
  const [authOpen, setAuthOpen] = React.useState(false);

  const refreshMe = React.useCallback(async () => {
    try {
      setMe(await fetchMe());
    } catch {
      setMe({ success: false, error: 'Unauthorized' });
    }
  }, []);

  React.useEffect(() => {
    void refreshMe();
  }, [refreshMe]);

  const logout = async () => {
    await fetch('/api/auth/logout', { method: 'POST', credentials: 'include' }).catch(() => null);
    await refreshMe();
    router.refresh();
    if (pathname !== '/') router.push('/');
  };

  const authed = me?.success === true;

  return (
    <header className="w-full border-b bg-background/80 backdrop-blur">
      <div className="container mx-auto px-4 py-3 flex items-center justify-between gap-3">
        <Link href="/" className="font-semibold text-foreground">
          DocSort
        </Link>

        <div className="flex items-center gap-2">
          {authed ? (
            <Button variant="outline" onClick={logout}>
              Logout
            </Button>
          ) : (
            <Button variant="outline" onClick={() => setAuthOpen(true)}>
              Sign in
            </Button>
          )}
        </div>
      </div>

      <AuthDialog
        open={authOpen}
        onOpenChange={setAuthOpen}
        onAuthed={async () => {
          await refreshMe();
          router.refresh();
        }}
      />
    </header>
  );
}
